2	import {
3	  quote,
4	  claim,
5	  insuranceSum,
6	  isKnownItemType,
7	  type Item,
8	} from "./claim-office.js";
9	
10	type QuoteStep = { op: "quote"; items: Item[] };
11	type ClaimStep = {
12	  op: "claim";
13	  policy: number;
14	  incident: { cause: string; damages: { itemType: string; amount: number }[] };
15	};
16	type Step = QuoteStep | ClaimStep;
17	
18	type Scenario = {
19	  customer: { yearsWithMHPCO: number };
20	  steps: Step[];
21	};
22	
23	type Policy = {
24	  items: Item[];
25	  remainingCap: number;
26	};
27	
28	type StepResult = { premium: number } | { payout: number; remainingCap: number };
29	
30	const CAP_MULTIPLIER = 2;
31	
32	async function readStdin(): Promise<string> {
33	  const chunks: Buffer[] = [];
34	  for await (const chunk of process.stdin) {
35	    chunks.push(chunk as Buffer);
36	  }
37	  return Buffer.concat(chunks).toString("utf8");
38	}
39	
40	function fail(message: string): never {
41	  console.error(message);
42	  process.exit(1);
43	}
44	
45	function validateItems(items: Item[]): void {
46	  for (const item of items) {
47	    if (!isKnownItemType(item.type)) {
48	      fail(`Unknown item type: ${item.type}`);
49	    }
50	  }
51	}
52	
53	function processQuote(
54	  step: QuoteStep,
55	  customerYears: number,
56	  previousContracts: number,
57	  policies: Policy[],
58	): StepResult {
59	  validateItems(step.items);
60	  const premium = quote({
61	    items: step.items,
62	    customerYears,
63	    previousContracts,
64	  });
65	  policies.push({
66	    items: step.items,
67	    remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
68	  });
69	  return { premium };
70	}
71	
72	function validateDamages(damages: { itemType: string }[], policyItems: Item[]): void {
73	  for (const damage of damages) {
74	    if (!policyItems.some((item) => item.type === damage.itemType)) {
75	      fail(`Damaged item type not in policy: ${damage.itemType}`);
76	    }
77	  }
78	}
79	
80	function processClaim(step: ClaimStep, policies: Policy[]): StepResult {
81	  const policy = policies[step.policy];
82	  validateDamages(step.incident.damages, policy.items);
83	  const result = claim({
84	    items: policy.items,
85	    remainingCap: policy.remainingCap,
86	    damages: step.incident.damages,
87	  });
88	  policy.remainingCap = result.remainingCap;
89	  return result;
90	}
91	
92	async function main() {
93	  const raw = await readStdin();
94	  const scenario: Scenario = JSON.parse(raw);
95	
96	  const results: StepResult[] = [];
97	  const policies: Policy[] = [];
98	  let previousContracts = 0;
99	
100	  for (const step of scenario.steps) {
101	    if (step.op === "quote") {
102	      results.push(
103	        processQuote(step, scenario.customer.yearsWithMHPCO, previousContracts, policies),
104	      );
105	      previousContracts += 1;
106	    } else {
107	      results.push(processClaim(step, policies));
108	    }
109	  }
110	
111	  console.log(JSON.stringify({ results }));
112	}
113	
114	main().catch((err) => {
115	  console.error(err instanceof Error ? err.message : String(err));
116	  process.exit(1);
117	});
